import{_ as e,o,c as t,a5 as r}from"./chunks/framework.B5tqjWbr.js";const f=JSON.parse('{"title":"概念：PCS 构网型 V/f 与下垂控制","description":"","frontmatter":{"date":"2026-06-22T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"概念：PCS 构网型 V/f 与下垂控制","tags":["power-electronics"],"status":"learning","summary":"本页是 `lessons/0044-pcs-grid-forming-vf-droop.html` 的源稿。"},"headers":[],"relativePath":"content/power/concepts/pcs/grid-forming-vf-droop.md","filePath":"content/power/concepts/pcs/grid-forming-vf-droop.md","lastUpdated":null}'),n={name:"content/power/concepts/pcs/grid-forming-vf-droop.md"};function s(i,a,l,p,c,d){return o(),t("div",null,[...a[0]||(a[0]=[r(`<h1 id="概念-pcs-构网型-v-f-与下垂控制" tabindex="-1">概念：PCS 构网型 V/f 与下垂控制 <a class="header-anchor" href="#概念-pcs-构网型-v-f-与下垂控制" aria-label="Permalink to &quot;概念：PCS 构网型 V/f 与下垂控制&quot;">​</a></h1><p>本页是 <code>lessons/0044-pcs-grid-forming-vf-droop.html</code> 的源稿。</p><h2 id="它是什么" tabindex="-1">它是什么 <a class="header-anchor" href="#它是什么" aria-label="Permalink to &quot;它是什么&quot;">​</a></h2><p>构网型控制（grid-forming control / GFM）自己建立电压和频率。电压频率控制（voltage-frequency control / V/f control）给出基本电压源参考，下垂控制（droop control）用于多机功率分担。</p><h2 id="为什么-ups-pcs-需要它" tabindex="-1">为什么 UPS/PCS 需要它 <a class="header-anchor" href="#为什么-ups-pcs-需要它" aria-label="Permalink to &quot;为什么 UPS/PCS 需要它&quot;">​</a></h2><p>UPS 离网逆变器和孤岛 PCS 都要建立负载电压，不能只依赖外部电网相位。</p><h2 id="数学形式" tabindex="-1">数学形式 <a class="header-anchor" href="#数学形式" aria-label="Permalink to &quot;数学形式&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>omega_ref = omega_nominal - Kp_droop * (P - P_ref)</span></span>
<span class="line"><span>V_ref = V_nominal - Kq_droop * (Q - Q_ref)</span></span></code></pre></div><h2 id="一个仿真任务" tabindex="-1">一个仿真任务 <a class="header-anchor" href="#一个仿真任务" aria-label="Permalink to &quot;一个仿真任务&quot;">​</a></h2><p>对负载加阶跃，观察 P/f 和 Q/V 下垂曲线。</p><h2 id="验收标准" tabindex="-1">验收标准 <a class="header-anchor" href="#验收标准" aria-label="Permalink to &quot;验收标准&quot;">​</a></h2><ul><li>能区分 GFL 和 GFM 的角度来源。</li><li>能写出 P-f、Q-V 下垂基本式。</li><li>能说明构网 PCS 与 UPS 离网逆变器的相似点。</li></ul><h2 id="导师问题" tabindex="-1">导师问题 <a class="header-anchor" href="#导师问题" aria-label="Permalink to &quot;导师问题&quot;">​</a></h2><p>GFL/GFM 模式边界通常由状态机还是上位机决定？</p>`,14)])])}const u=e(n,[["render",s]]);export{f as __pageData,u as default};
